
public class 지역변수 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		char c='A';
		for(int i=0; i<5;i++) {
			System.out.println(c++);
		}
		System.out.println();
		for (int i=0; i<5;i++) {
			char d='A';
			System.out.println(d++);
		}
		

	}

}
